INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6b6eee65-8e8f-4939-944f-ae4e80168294',
  '00000000-0000-0000-0000-000000000001',
  $escape$IPFS — Understanding Content Addressing with CIDs$escape$,
  $escape$IPFS uses Content-Addressed Storage, where files are addressed by their content, rather than their location. This is achieved through the use of Content Identifiers (CIDs), which are unique hashes of the file's contents. CIDs are used to identify and retrieve files from the IPFS network. The `ipfs add` command is used to add files to the network and generate a CID. The `ipfs get` command can then be used to retrieve a file by its CID. IPFS also uses a Distributed Hash Table (DHT) to store and retrieve CIDs, allowing for efficient lookup and retrieval of files. Pinning a file ensures it remains available on the network, even if the original node goes offline.$escape$,
  $escape$const ipfs = require('ipfs-http-client');
const file = 'path/to/file';
const cid = await ipfs.add(file);
console.log(cid.path);$escape$,
  $escape$javascript$escape$,
